// ============================================================================
// In-process subagent runner
// ============================================================================

interface SubagentContext {
	modelRegistry?: ModelRegistry;
	model?: any; // Parent's current model
}

async function runSubagent(
	specialist: Specialist,
	task: string,
	cwd: string,
	parentCtx?: SubagentContext,
	signal?: AbortSignal,
	onUpdate?: (update: any) => void,
	orchestratorActivity?: OrchestratorActivity,
): Promise<{ output: string; turns: number }> {
	try {
		// Use parent's model registry if available, otherwise create empty
		const authStorage = AuthStorage.create();
		const modelRegistry = parentCtx?.modelRegistry ?? ModelRegistry.inMemory(authStorage);

		// Resolve model: specialist.model > parent's model > registry fallback
		let model;
		if (specialist.model) {
			// Specialist has custom model specified (format: "provider/id")
			const slashIdx = specialist.model.indexOf("/");
			if (slashIdx > 0) {
				const provider = specialist.model.slice(0, slashIdx);
				const id = specialist.model.slice(slashIdx + 1);
				model = getModel(provider, id);
			}
		} else if (parentCtx?.model) {
			// Inherit parent's model
			model = parentCtx.model;
		}

		// Fallback: use first available model from registry
		if (!model) {
			const available = modelRegistry.getAvailable();
			if (available.length > 0) {
				model = available[0];
			}
		}

		if (!model) {
			return { output: "[error] No model available for subagent. Check API key configuration.", turns: 0 };
		}

		// Load extensions and skills for the subagent, but flag the context
		// so the orchestrator extension skips re-registering its tools
		// and before_agent_start handler (avoids infinite delegation loop).
		_batchLoadSubagent++;
		const loader = new DefaultResourceLoader({
			cwd,
			agentDir: getAgentDir(),
			systemPromptOverride: () => specialist.systemPrompt,
		});
		await loader.reload();
		_batchLoadSubagent--;

		const { session } = await createAgentSession({
			cwd,
			model,
			tools: specialist.tools,
			resourceLoader: loader,
			sessionManager: SessionManager.inMemory(cwd),
			authStorage,
			modelRegistry,
		});

		let output = "";
		let turns = 0;
		const feed = createActivityFeed();
		feed.goal = shortenLabel(task);

		const unsubscribe = session.subscribe((event) => {
			if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
				output += event.assistantMessageEvent.delta;
				parseTextForFeed(feed, event.assistantMessageEvent.delta);
			}
			if (event.type === "message_end") {
				if (event.message?.role === "assistant") {
					turns++;
					if (feed.steps.length > 0 && feed.currentStep < feed.steps.length) {
						completeCurrentStep(feed);
					}
					// Use combined progress if orchestrator activity available, else standalone feed
					const text = orchestratorActivity
						? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
						: renderActivityFeed(specialist.name, feed);
					lastActivityFeedText = text;
					if (planTUI) planTUI.requestRender(true);
					onUpdate?.({
						content: [{ type: "text", text }],
						details: { specialist: specialist.name, status: "running", turns },
					});
				}
			}
			if (event.type === "tool_execution_start") {
				const substepLabel = toolCallToSubstep(event.toolName, event.args);
				addSubstep(feed, substepLabel);
				const text = orchestratorActivity
					? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
					: renderActivityFeed(specialist.name, feed);
				lastActivityFeedText = text;
				if (planTUI) planTUI.requestRender(true);
				onUpdate?.({
					content: [{ type: "text", text }],
					details: { specialist: specialist.name, status: "running", tool: event.toolName },
				});
			}
			if (event.type === "tool_execution_end") {
				completeLastSubstep(feed);
				const text = orchestratorActivity
					? renderCombinedProgress(orchestratorActivity, specialist.name, feed, orchestratorGoal)
					: renderActivityFeed(specialist.name, feed);
				lastActivityFeedText = text;
				if (planTUI) planTUI.requestRender(true);
				onUpdate?.({
					content: [{ type: "text", text }],
					details: { specialist: specialist.name, status: "running" },
				});
			}
		});

		// Abort handler — cancel subagent when parent aborts
		const abortHandler = () => {
			session.abort();
		};
		if (signal) {
			if (signal.aborted) abortHandler();
			signal.addEventListener("abort", abortHandler, { once: true });
		}

		try {
			await session.prompt(task);
		} catch (error) {
			output = `[error] ${error instanceof Error ? error.message : String(error)}`;
		} finally {
			unsubscribe();
			if (signal) signal.removeEventListener("abort", abortHandler);
			session.dispose();
		}

		// Compress + cap output before returning to main agent
		let finalOutput = compressOutput(output || "(no output)");
		if (finalOutput.length > OUTPUT_CAP) {
			finalOutput = finalOutput.slice(0, OUTPUT_CAP) + "\n\n[output truncated]";
		}

		return { output: finalOutput, turns };
	} catch (error) {
		// Catch ALL errors from initialization (DefaultResourceLoader, createAgentSession, etc.)
		const msg = error instanceof Error ? error.message : String(error);
		const stack = error instanceof Error ? error.stack : "";
		return { output: `[error] Subagent init failed: ${msg}${stack ? "\n" + stack.split("\n").slice(0, 5).join("\n") : ""}`, turns: 0 };
	}
}

// ============================================================================
// Parallel runner
// ============================================================================

async function runParallel(
	tasks: Array<{ specialist: Specialist; task: string }>,
	cwd: string,
	parentCtx?: SubagentContext,
	signal?: AbortSignal,
	onUpdate?: (update: any) => void,
): Promise<Array<{ specialist: string; output: string; error?: string }>> {
	const concurrency = Math.min(MAX_PARALLEL, tasks.length);
	const results: Array<{ specialist: string; output: string; error?: string }> = new Array(tasks.length);
	let nextIndex = 0;

	const workers = Array(concurrency).fill(null).map(async () => {
		while (nextIndex < tasks.length) {
			const i = nextIndex++;
			const { specialist, task } = tasks[i];
			try {
				const result = await runSubagent(specialist, task, cwd, parentCtx, signal, onUpdate);
				results[i] = { specialist: specialist.name, output: result.output };
			} catch (error) {
				results[i] = {
					specialist: specialist.name,
					output: "",
					error: error instanceof Error ? error.message : String(error),
				};
			}
		}
	});

	await Promise.all(workers);
	return results;
}

// ============================================================================
// The Extension
// ============================================================================

export default function (pi: ExtensionAPI) {

	// ── Guard: Skip registration when loading for a subagent session ──────
	// When _batchLoadSubagent > 0, this extension is being loaded as part
	// of a subagent's resource discovery. Registering the orchestrator
	// tools and before_agent_start handler would cause:
	//   1. Subagent gets "Orchestrator Mode" injected into its system prompt
	//   2. delegate/parallel/chain tools become available, risking recursion
	//
	// Subagents still get all other extensions (token-saver, pi-web-access)
	// and skills (caveman, librarian) — only the orchestrator opts out.
	if (_batchLoadSubagent > 0) return;

	// ── System Prompt: Tell the agent to ALWAYS delegate ──────────────────

	pi.on("before_agent_start", async (event, ctx) => {
		// Reset orchestrator activity for new session
		orchestratorActivity = null;
		orchestratorGoal = "";
		clearPlanPanel(ctx);

		const delegationInstructions = `
## Orchestrator Mode — ALWAYS DELEGATE

You are an orchestrator. You NEVER do the work yourself. You plan and delegate.

### Rules:
1. **NEVER read files directly** — delegate to a subagent
2. **NEVER run bash commands** — delegate to a subagent
3. **NEVER write/edit files** — delegate to a subagent
4. **ALWAYS break tasks into subtasks** before delegating
5. **ALWAYS synthesize** subagent outputs into a coherent response
6. **ALWAYS use \`edit\` tool for code changes** — if the exact-text match fails, retry with \`write\` (full file content). NEVER fall back to \`bash\` + \`sed\`/\`awk\`. Both \`edit\` and \`write\` trigger lint-guard syntax check.

### Specialist roster:
- **scout** — Fast codebase investigation (read-only, haiku)
- **coder** — Implementation (read/write/bash)
- **reviewer** — Code review (read-only, thorough)
- **researcher** — Question answering (read-only)
- **writer** — Documentation (read/write)

### Tools:
- \`delegate(specialist, task)\` — single specialist
- \`parallel(tasks)\` — multiple specialists simultaneously
- \`chain(steps)\` — sequential with {previous} placeholder

### Workflow for every task:
1. Analyze the request
2. Break into subtasks
3. Delegate with the right tool
4. Synthesize results into a final answer

### Example:
User: "Add error handling to main.ts"
You: delegate(scout, "Find main.ts and understand current error handling") →
     delegate(coder, "Add try/catch based on this: {scout output}") →
     delegate(reviewer, "Review changes: {coder output}")

Your response should be the synthesized summary — NOT the implementation details.
`;

		// Filter tools: delegation + read-only (no edit/write)
		if (event.systemPromptOptions?.selectedTools) {
			event.systemPromptOptions.selectedTools = [
				"delegate", "parallel", "chain",
				"read", "bash", "grep", "find",
			];
		}

		return {
			systemPrompt: event.systemPrompt + "\n" + delegationInstructions,
		};
	});

	// ── Safety net: Block non-delegation tool calls ──────────────────────
	// NOTE: Disabled — selectedTools filter in before_agent_start is sufficient.
	// Tool_call blocking interferes with subagent sessions in the same process.
	// pi.on("tool_call", async (event, ctx) => {
	//     if (event.toolName !== "delegate" && event.toolName !== "parallel" && event.toolName !== "chain") {
	//         return { block: true, reason: `Orchestrator mode: use delegate() instead of ${event.toolName}` };
	//     }
	// });

	// ── Box-wrapping helpers (standalone functions, no `this` binding issues) ──

	function wrapInBox(lines: string[], boxWidth: number): string {
		const out: string[] = [];
		for (const line of lines) {
			const clean = line.replace(/\x1b\[[0-9;]*m/g, "");
			const padded = clean.length > boxWidth - 4
				? clean.slice(0, boxWidth - 4)
				: clean + " ".repeat(boxWidth - 4 - clean.length);
			out.push(`│ ${padded} │`);
		}
		out.push(`╰${("─").repeat(boxWidth - 2)}╯`);
		return out.join("\n");
	}

	function boxWidthFor(name: string): number {
		if (!name) return 0;
		return 3 + name.length + 1 + Math.max(0, BOX_INNER_WIDTH - name.length) + 1;
	}

	function specDisplayName(params: any, details: any): string {
		const raw = params?.specialist || details?.specialist || "";
		return raw ? raw.charAt(0).toUpperCase() + raw.slice(1) : "";
	}

	// ── Tool: delegate — Single, parallel, or chain mode ──────────────────

	pi.registerTool({
		name: "delegate",
		label: "delegate",
		description: `Delegate work to specialist subagents. Three modes:\n- Single: { specialist, task }\n- Parallel: { tasks: [{specialist, task}, ...] }\n- Chain: { steps: [{specialist, task}, ...] } with {previous} placeholder`,
		renderShell: "self",
		parameters: Type.Object({
			specialist: Type.Optional(Type.String({
				description: "Specialist: scout, coder, reviewer, researcher, writer",
			})),
			task: Type.Optional(Type.String({
				description: "Task description",
			})),
			tasks: Type.Optional(Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name" }),
					task: Type.String({ description: "Task description" }),
				}),
				{ description: "Parallel mode: run these tasks simultaneously" },
			)),
			steps: Type.Optional(Type.Array(
				Type.Object({
					specialist: Type.String({ description: "Specialist name" }),
					task: Type.String({ description: "Task. Use {previous} for prior output." }),
				}),
				{ description: "Chain mode: run sequentially, pass output to next" },
			)),
		}),

		// ── Render: what shows when tool is invoked ──
		renderCall(args, theme, _context) {
			if (args.specialist) {
				const name = args.specialist.charAt(0).toUpperCase() + args.specialist.slice(1);
				const inner = `${name} ${("─").repeat(Math.max(0, BOX_INNER_WIDTH - name.length))}`;
				return new Text(theme.fg("toolTitle", `╭─ ${inner}╮`), 0, 0);
			}
			if (args.tasks) {
				const names = args.tasks.map((t: any) => t.specialist).join(", ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ parallel [${args.tasks.length}] `)) + theme.fg("dim", names), 0, 0);
			}
			if (args.steps) {
				const names = args.steps.map((s: any) => s.specialist).join(" → ");
				return new Text(theme.fg("toolTitle", theme.bold(`→ chain `)) + theme.fg("dim", names), 0, 0);
			}
			return new Text(theme.fg("toolTitle", theme.bold(`→ `)) + theme.fg("accent", args.specialist || "?"), 0, 0);
		},

		// ── Render: what shows during/after execution ──
		renderResult(result, { isPartial, expanded }, theme, context) {
			const details = result.details as any;
			const ctxParams = (context as any)?.params as Record<string, any> | undefined;
			const content = result.content?.[0];
			const text = content?.type === "text" ? content.text : "";

			const specName = specDisplayName(ctxParams, details);
			const bWidth = boxWidthFor(specName);

			if (isPartial) {
				if (text && bWidth > 0) {
					return new Text(theme.fg("warning", wrapInBox(text.split("\n"), bWidth)), 0, 0);
				}
				if (details?.specialist && bWidth > 0) {
					return new Text(theme.fg("warning", wrapInBox([`⠋ ${details.specialist}...`], bWidth)), 0, 0);
				}
				if (bWidth > 0) {
					return new Text(theme.fg("warning", wrapInBox(["⠋ working..."], bWidth)), 0, 0);
				}
				return new Text(theme.fg("warning", "⠋ working..."), 0, 0);
			}

			// Single mode — show activity feed in box (all ✓, never collapses)
			if (details?.specialist && bWidth > 0) {
				const feedText = lastActivityFeedText || text || `✓ ${details.specialist}`;
				return new Text(theme.fg("success", wrapInBox(feedText.split("\n"), bWidth)), 0, 0);
			}

			// Parallel mode — show activity feed if stored
			if (details?.activityFeed) {
				const lines = details.activityFeed.split("\n");
				const pBoxWidth = Math.max(34, (lines[0]?.length || 30) + 4);
				return new Text(theme.fg("success", wrapInBox(lines, pBoxWidth)), 0, 0);
			}
			if (details?.results) {
				const ok = details.results.filter((r: any) => !r.error).length;
				const total = details.results.length;
				const summary = `✓ ${ok}/${total} completed`;
				const lines: string[] = [summary];
				const pBoxWidth = Math.max(summary.length + 4, 30);
				return new Text(theme.fg("success", wrapInBox(lines, pBoxWidth)), 0, 0);
			}

			// Chain mode — show activity feed if stored
			if (details?.activityFeed) {
				const lines = details.activityFeed.split("\n");
				const cBoxWidth = Math.max(34, (lines[0]?.length || 30) + 4);
				return new Text(theme.fg("success", wrapInBox(lines, cBoxWidth)), 0, 0);
			}
			if (details?.steps) {
				const summary = `✓ ${details.steps} steps completed`;
				const lines: string[] = [summary];
				const cBoxWidth = Math.max(summary.length + 4, 30);
				return new Text(theme.fg("success", wrapInBox(lines, cBoxWidth)), 0, 0);
			}

			return new Text(theme.fg("success", "✓ done"), 0, 0);
		},

		async execute(toolCallId, params, signal, onUpdate, ctx) {
			// ── Parallel mode ──
			if (params.tasks) {
				if (params.tasks.length > MAX_PARALLEL) {
					return { content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }], details: {} };
				}

				const resolved = params.tasks
					.map((t) => {
						const spec = SPECIALISTS[t.specialist];
						if (!spec) return null;
						return { specialist: spec, task: t.task };
					})
					.filter(Boolean) as Array<{ specialist: Specialist; task: string }>;

				if (resolved.length === 0) {
					return { content: [{ type: "text", text: "No valid specialists found." }], details: {} };
				}

				resetOrchestratorActivity();

				// Stream status per specialist
				let running = 0;
				const results: Array<{ specialist: string; output: string; error?: string }> = new Array(resolved.length);
				const updateStatus = () => {
					const names = resolved.map((r, i) => {
						const done = results[i]?.output !== undefined;
						return done ? `✓${r.specialist.name}` : `...${r.specialist.name}`;
					}).join(" ");
					onUpdate?.({
						content: [{ type: "text", text: `⠋ ${names}` }],
						details: { status: "running", specialist: names },
					});
				};

				// Run in parallel with status updates
				const promises = resolved.map(async (r, i) => {
					running++;
					updateStatus();
					try {
						const result = await runSubagent(r.specialist, r.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);
						results[i] = { specialist: r.specialist.name, output: result.output };
					} catch (error) {
						results[i] = { specialist: r.specialist.name, output: "", error: error instanceof Error ? error.message : String(error) };
					}
					running--;
					updateStatus();
				});

				await Promise.all(promises);

				const output = results
					.map((r) => `### [${r.specialist}] ${r.error ? "ERROR" : "OK"}\n\n${r.output}`)
					.join("\n\n---\n\n");

				return {
					content: [{ type: "text", text: output }],
					details: { status: "done", results: results.map((r) => ({ specialist: r.specialist, outputLength: r.output.length, error: r.error })) },
				};
			}

			// ── Chain mode ──
			if (params.steps) {
				const chainResults: Array<{ step: number; specialist: string; output: string; error?: string }> = [];
				let previousOutput = "";

				resetOrchestratorActivity();

