renderResult(result, { isPartial, expanded }, theme, _context) {
	const details = result.details as any;
	const content = result.content?.[0];
	const text = content?.type === "text" ? content.text : "";

	if (isPartial) {
		if (text) {
			return new Text(theme.fg("warning", text), 0, 0);
		}
		return new Text(theme.fg("warning", "⠋ Running..."), 0, 0);
	}

// Show activity feed if stored (never collapses)
	if (details?.activityFeed) {
		return new Text(theme.fg("success", details.activityFeed), 0, 0);
	}

	if (details?.steps) {
		return new Text(theme.fg("success", `✓ ${details.steps} steps completed`), 0, 0);
	}

	return new Text(theme.fg("success", "✓ done"), 0, 0);
},

